// Regular function
function add(a, b) {
  return a + b;
}

// Arrow function — equivalent
const add = (a, b) => {
  return a + b;
};

// Arrow function — concise body (implicit return)
const add = (a, b) => a + b;

// No parameters — use empty parens
const greet = () => 'Hello!';

// One parameter — parens optional
const double = n => n * 2;
const double = (n) => n * 2; // also valid

// Multiple parameters — parens required
const add = (a, b) => a + b;

// Default parameters
const greet = (name = 'World') => `Hello, ${name}!`;

// ❌ Parsed as a block — returns undefined
const getUser = id => { id: id, name: 'Alice' };

// ✅ Wrap in () to signal an expression
const getUser = id => ({ id, name: 'Alice' });

console.log(getUser(1)); // { id: 1, name: 'Alice' }

// Problem with regular function in a callback:
const timer = {
  count: 0,
  start: function() {
    setInterval(function() {
      this.count++; // ❌ 'this' is not the timer object here!
      // In non-strict mode, this === window; in strict mode, this === undefined
    }, 1000);
  }
};

// Arrow function solution — inherits 'this' from start():
const timer = {
  count: 0,
  start: function() {
    setInterval(() => {
      this.count++; // ✅ 'this' is the timer object
    }, 1000);
  }
};

function Counter() {
  const [count, setCount] = useState(0);

  // Arrow function defined outside JSX — preferred
  const handleIncrement = () => setCount(c => c + 1);
  const handleDecrement = () => setCount(c => c - 1);
  const handleReset = () => setCount(0);

  return (
    <div>
      <button onClick={handleDecrement}>-</button>
      <span>{count}</span>
      <button onClick={handleIncrement}>+</button>
      <button onClick={handleReset}>Reset</button>
    </div>
  );
}

// Arrow functions can be written inline:
function List({ items, onDelete }) {
  return (
    <ul>
      {items.map(item => (
        <li key={item.id}>
          {item.name}
          {/* Inline arrow function — creates a new function on each render */}
          <button onClick={() => onDelete(item.id)}>Delete</button>
        </li>
      ))}
    </ul>
  );
}

function TaskList({ tasks }) {
  const activeTasks = tasks
    .filter(task => !task.done)
    .map(task => ({ ...task, title: task.title.trim() }));

  return (
    <ul>
      {activeTasks.map(task => (
        <li key={task.id}>{task.title}</li>
      ))}
    </ul>
  );
}

// Arrow functions as state updaters:
const [count, setCount] = useState(0);

// Functional update form — receives the previous state
setCount(prev => prev + 1);
setCount(prev => Math.max(0, prev - 1)); // won't go below 0

// With objects:
const [user, setUser] = useState({ name: 'Alice', age: 25 });
setUser(prev => ({ ...prev, age: prev.age + 1 }));

// Arrow function components are valid and common
const Button = ({ label, onClick, variant = 'primary' }) => (
  <button className={`btn btn-${variant}`} onClick={onClick}>
    {label}
  </button>
);

// But function declarations are also fine — both styles are used
function Button({ label, onClick, variant = 'primary' }) {
  return (
    <button className={`btn btn-${variant}`} onClick={onClick}>
      {label}
    </button>
  );
}

// ❌ Looks like it returns an object, actually returns undefined
const getUser = id => { id, name: 'Alice' }; // parsed as a block

// ✅
const getUser = id => ({ id, name: 'Alice' });

// ❌ Calls handleSubmit immediately on render (note the ())
<button onClick={handleSubmit()}>Submit</button>

// ✅ Passes the function reference — called when button is clicked
<button onClick={handleSubmit}>Submit</button>

// ✅ If you need to pass arguments, wrap in an arrow function:
<button onClick={() => handleSubmit(formData)}>Submit</button>

// ❌ Arrow functions don't have their own 'this'
const counter = {
  count: 0,
  // Arrow function — 'this' is not the counter object
  increment: () => { this.count++; }, // 'this' is the enclosing context (probably window/undefined)
};

// ✅ Use a regular function for object methods that need 'this'
const counter = {
  count: 0,
  increment: function() { this.count++; }, // ✅
};
